import requests


CLIENT_ID = os.getenv('MAERSK_CLIENT_ID') if not os.getenv('MAERSK_CLIENT_ID')==None else ""
CLIENT_ID = CLIENT_ID if CLIENT_ID is not None else ""

CLIENT_SECRET = os.getenv('MAERSK_CLIENT_SECRET') if not os.getenv('MAERSK_CLIENT_SECRET')==None else ""
CLIENT_SECRET = CLIENT_SECRET if CLIENT_SECRET is not None else ""

TRACKING_URL ="https://api.maersk.com/synergy/tracking/266802785?operator=MAEU"

def build_url(booking:str)->str:
    return f"https://api.maersk.com/synergy/tracking/{booking}?operator=MAEU"

def checkingMaersk(booking_num:str):
    headers = {
        "accept" : "application/json",
        "accept-encoding": "gzip, deflate, br, zstd",
        "accept-language": "en-US,en;q=0.9",
        "Cache-Control": "no-cache",
        'Consumer-Key': f'{CLIENT_ID}',
        "Content-Type": "application/x-www-form-urlencoded",
        "api-version" : "v2",
        "akamai-bm-telemetry":"a=9BAC3A26F94089162475653582EA0E60&&&&&&sensor_",
        "Origin":"https://www.maersk.com",
        "Referer": "https://www.maersk.com",
        'sec-ch-ua': '"Chromium";v="143", "Not A(Brand";v="24"',
        'sec-ch-ua-mobile': '?0',
        'sec-ch-ua-platform': '"Windows"',
        "user-agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/143.0.0.0 Safari/537.36",
        
    }
    
    response = requests.get(build_url(booking_num), headers=headers, timeout=30)
    response.raise_for_status()

    data = response.json()
    # access_token = data["access_token"]
    # expires_in = data["expires_in"]

    print(data)
    # print("Expires in (seconds):", expires_in)
    
if __name__ == "__main__":
    checkingMaersk("266802785")